// src/views/liste.owner.js
import React, { useState } from "react";
import FooterRecharche from "../components/Footers/footer.recharche";
import Navbar from "../components/Navbars/AuthNavbar";
import OwnerCard from "components/Common/OwnerCard";
import { useHistory } from "react-router-dom";

export default function ListeOwner() {
  const history = useHistory();
  const [searchTerm, setSearchTerm] = useState("");
  
  // Pour simuler le rôle de l'utilisateur (true = manager, false = visiteur)
  // Dans la réalité, ceci viendrait de votre système d'authentification
  const [isManager, setIsManager] = useState(true);
  
  const [owners, setOwners] = useState([
    {
      id: 1,
      name: "Ahmed Benali",
      location: "Alger, Algérie",
      bio: "Passionné par la cuisine traditionnelle algérienne, je souhaite ouvrir mon propre restaurant pour faire découvrir les saveurs authentiques de notre terroir.",
      image: "https://randomuser.me/api/portraits/men/32.jpg",
      restaurantId: null
    },
    {
      id: 2,
      name: "Jean Dupont",
      location: "Paris, France",
      bio: "Amoureux du café et de la pâtisserie française, je cherche à reprendre un établissement pour partager ma passion.",
      image: "https://randomuser.me/api/portraits/men/45.jpg",
      restaurantId: null
    },
    {
      id: 3,
      name: "Marco Rossi",
      location: "Rome, Italie",
      bio: "Chef italien avec 25 ans d'expérience, je souhaite devenir propriétaire de mon propre restaurant.",
      image: "https://randomuser.me/api/portraits/men/68.jpg",
      restaurantId: null
    },
    {
      id: 4,
      name: "Kenji Tanaka",
      location: "Tokyo, Japon",
      bio: "Maître sushi formé au Japon, je cherche un établissement pour partager l'art du sushi authentique.",
      image: "https://randomuser.me/api/portraits/men/89.jpg",
      restaurantId: null
    },
    {
      id: 5,
      name: "Sophia Martinez",
      location: "Lyon, France",
      bio: "Pâtissière passionnée, je rêve d'ouvrir ma propre boutique de pâtisseries artisanales.",
      image: "https://randomuser.me/api/portraits/women/45.jpg",
      restaurantId: null
    },
    {
      id: 6,
      name: "Carlos Mendez",
      location: "Barcelone, Espagne",
      bio: "Spécialiste de la cuisine espagnole, je veux ouvrir un restaurant de tapas authentiques.",
      image: "https://randomuser.me/api/portraits/men/52.jpg",
      restaurantId: null
    },
    {
      id: 7,
      name: "Yuki Yamamoto",
      location: "Osaka, Japon",
      bio: "Chef spécialisé dans les ramen, je cherche un local pour ouvrir mon premier restaurant.",
      image: "https://randomuser.me/api/portraits/women/68.jpg",
      restaurantId: null
    },
    {
      id: 8,
      name: "Mohamed Ali",
      location: "Casablanca, Maroc",
      bio: "Expert en cuisine marocaine, je souhaite faire découvrir les tajines et couscous authentiques.",
      image: "https://randomuser.me/api/portraits/men/91.jpg",
      restaurantId: null
    }
  ]);

  const [claimedOwners, setClaimedOwners] = useState([]);

  const filteredOwners = owners.filter(owner =>
    owner.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    owner.location.toLowerCase().includes(searchTerm.toLowerCase()) ||
    owner.bio.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleClaimRestaurant = (owner) => {
    // Mettre à jour le propriétaire avec le restaurantId
    const updatedOwners = owners.map(o => 
      o.id === owner.id ? { ...o, restaurantId: Date.now() } : o
    );
    setOwners(updatedOwners);
    setClaimedOwners([...claimedOwners, owner.id]);
    
    // Sauvegarder dans localStorage
    const claimedData = {
      ownerId: owner.id,
      ownerName: owner.name,
      restaurantId: Date.now(),
      date: new Date().toISOString()
    };
    localStorage.setItem(`claimed_restaurant_${owner.id}`, JSON.stringify(claimedData));
    
    // Optionnel: afficher un message de succès
    console.log(`✅ Restaurant attribué à ${owner.name}`);
  };

  const handleSearch = (value) => {
    setSearchTerm(value);
  };

  const style = `
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }
    
    @keyframes fadeIn {
      from { opacity: 0; transform: translateY(20px); }
      to { opacity: 1; transform: translateY(0); }
    }
    
    .owners-container {
      background: linear-gradient(135deg, #0a0a2a, #1a1a3a, #0d0d2b);
      min-height: 100vh;
      padding-top: 80px;
      padding-bottom: 80px;
    }
    
    .owners-header {
      text-align: center;
      margin-bottom: 30px;
      padding: 0 20px;
    }
    
    .owners-title {
      font-size: 2rem;
      font-weight: bold;
      color: white;
      margin-bottom: 10px;
    }
    
    .owners-subtitle {
      font-size: 0.9rem;
      color: rgba(255,255,255,0.6);
    }
    
    .owners-grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
      gap: 25px;
      max-width: 1400px;
      margin: 0 auto;
      padding: 20px;
    }
    
    .manager-badge {
      position: fixed;
      bottom: 20px;
      right: 20px;
      background: #22c55e;
      color: white;
      padding: 10px 20px;
      border-radius: 30px;
      font-size: 0.85rem;
      font-weight: bold;
      z-index: 100;
      box-shadow: 0 5px 15px rgba(34,197,94,0.3);
      display: flex;
      align-items: center;
      gap: 8px;
    }
    
    .empty-state {
      text-align: center;
      padding: 60px 20px;
      color: rgba(255,255,255,0.5);
      grid-column: 1 / -1;
    }
    
    .empty-state-icon {
      font-size: 4rem;
      margin-bottom: 15px;
      opacity: 0.5;
    }
    
    .empty-state-title {
      font-size: 1.2rem;
      margin-bottom: 8px;
      color: rgba(255,255,255,0.7);
    }
    
    .empty-state-subtitle {
      font-size: 0.85rem;
      color: rgba(255,255,255,0.4);
    }
    
    .results-count {
      text-align: center;
      color: rgba(255,255,255,0.5);
      font-size: 0.85rem;
      margin-bottom: 10px;
    }
    
    @media (max-width: 768px) {
      .owners-grid {
        grid-template-columns: 1fr;
        padding: 15px;
        gap: 20px;
      }
      
      .owners-title {
        font-size: 1.5rem;
      }
      
      .manager-badge {
        bottom: 15px;
        right: 15px;
        padding: 6px 12px;
        font-size: 0.7rem;
      }
    }
  `;

  return (
    <>
      <style>{style}</style>
      <Navbar />
      
      <div className="owners-container">
        <div className="owners-header">
          <h1 className="owners-title">👨‍🍳 Propriétaires de restaurants</h1>
          <p className="owners-subtitle">
            Découvrez les futurs propriétaires et attribuez-leur un restaurant
          </p>
        </div>
        
        <div className="results-count">
          {filteredOwners.length} propriétaire(s) trouvé(s)
        </div>
        
        <div className="owners-grid">
          {filteredOwners.length === 0 ? (
            <div className="empty-state">
              <div className="empty-state-icon">🔍</div>
              <h3 className="empty-state-title">Aucun propriétaire trouvé</h3>
              <p className="empty-state-subtitle">Essayez une autre recherche</p>
            </div>
          ) : (
            filteredOwners.map(owner => (
              <OwnerCard 
                key={owner.id}
                owner={owner}
                isManager={isManager}
                onClaimRestaurant={handleClaimRestaurant}
              />
            ))
          )}
        </div>
      </div>
      
      <FooterRecharche 
        type="owners"
        onSearch={handleSearch}
        placeholder="🔍 Rechercher un propriétaire par nom, ville ou description..."
      />
      
      {isManager && (
        <div className="manager-badge">
          👑 Mode Manager
          <span style={{ fontSize: '0.7rem', opacity: 0.8 }}>- Vous pouvez attribuer les restaurants</span>
        </div>
      )}
    </>
  );
}
